# === ViFi site Decap CMS install (auto-generated) ===
# 10 files (some overwrite existing)
# RUN FROM INSIDE the vifi-site repo: cd C:\Users\zpopowitz1\vifi-site

$ErrorActionPreference = 'Stop'

# Anchor to script location (so CWD doesn't matter), but verify we're inside vifi-site.
$baseDir = if ($PSScriptRoot) { $PSScriptRoot } else { (Get-Location).Path }
if (-not (Test-Path (Join-Path $baseDir 'package.json'))) {
    Write-Error "This script must live inside the vifi-site repo (next to package.json). Move it there and re-run."
    exit 1
}

Write-Host "Installing Decap CMS files into: $baseDir" -ForegroundColor Cyan

# Make sure subdirectories exist
foreach ($d in @('src/content', 'src/content/landing', 'public/admin', 'api/oauth')) {
    $full = Join-Path $baseDir $d
    if (-not (Test-Path $full)) { New-Item -ItemType Directory -Path $full | Out-Null }
}

function Write-FileFromBase64($relPath, $b64, $action) {
    $full = Join-Path $baseDir $relPath
    $exists = Test-Path $full
    $bytes = [Convert]::FromBase64String($b64)
    [System.IO.File]::WriteAllBytes($full, $bytes)
    $tag = if ($exists) { 'updated' } else { 'created' }
    Write-Host "  $tag $relPath ($($bytes.Length) bytes)"
}

