'@
Write-FileFromBase64 'README.md' $b64 'overwrite'

Write-Host ''
Write-Host 'Decap CMS files installed. Next:' -ForegroundColor Green
Write-Host '  1. npm run build              # verify everything still builds'
Write-Host '  2. git status                 # review changes'
Write-Host '  3. git checkout -b feat/decap-cms'
Write-Host '  4. git add -A'
Write-Host '  5. git commit -m "feat: add Decap CMS for visual content editing"'
Write-Host '  6. git push -u origin feat/decap-cms'
Write-Host '  7. Open a PR -> merge to main -> Vercel deploys.'
Write-Host ''
Write-Host 'Then: README.md -> CMS / OAuth setup (one-time)'
Write-Host '  - Create GitHub OAuth app at github.com/settings/developers'
Write-Host '  - Set OAUTH_GITHUB_CLIENT_ID + OAUTH_GITHUB_CLIENT_SECRET in Vercel env vars'
Write-Host '  - Redeploy, visit vifi.health/admin'
